import{_ as t,o,c as e,a4 as d}from"./chunks/framework.BMymQDdR.js";const G=JSON.parse('{"title":"环境配置","description":"","frontmatter":{},"headers":[],"relativePath":"v3/designer/Environment-Config.md","filePath":"zh/v3/designer/Environment-Config.md","lastUpdated":1780630099000}'),a={name:"v3/designer/Environment-Config.md"},r=d('<h1 id="环境配置" tabindex="-1">环境配置 <a class="header-anchor" href="#环境配置" aria-label="Permalink to &quot;环境配置&quot;">​</a></h1><p>环境配置用于设置设计器运行所需的 Go 语言环境，通过 <strong>设置 &gt; 环境配置</strong>（快捷键 <code>Ctrl+F10</code> / macOS <code>Cmd+F10</code>）打开。</p><h2 id="go-root-路径" tabindex="-1">Go Root 路径 <a class="header-anchor" href="#go-root-路径" aria-label="Permalink to &quot;Go Root 路径&quot;">​</a></h2><p>设置 Go 语言安装根目录（GOROOT）。设计器使用此路径查找 Go 编译器和工具链。</p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>输入类型</th></tr></thead><tbody><tr><td>Go Root</td><td>Go SDK 安装根目录路径</td><td>可编辑下拉框 + 目录选择器</td></tr></tbody></table><p><strong>使用方式：</strong></p><ul><li>点击下拉框可选择之前配置过的 Go 安装路径</li><li>点击目录选择器按钮，浏览并选择 Go 安装目录</li><li>设计器会验证所选目录下是否存在 <code>bin/go</code>（Linux/macOS）或 <code>bin\\go.exe</code>（Windows）</li></ul><p><strong>保存后的效果：</strong></p><ul><li>设置 <code>GOROOT</code> 环境变量为所选路径</li><li>将 <code>&lt;Go Root&gt;/bin</code> 添加到 <code>PATH</code> 环境变量</li><li>配置保存在设计器全局配置文件 <code>~/.energy/config.json</code> 中，对当前项目生效</li></ul><h2 id="go-版本检测" tabindex="-1">Go 版本检测 <a class="header-anchor" href="#go-版本检测" aria-label="Permalink to &quot;Go 版本检测&quot;">​</a></h2><p>设计器会自动检测系统中已安装的 Go 版本，并显示检测状态。</p><p><strong>要求：</strong></p><ul><li>Go 1.20 或更高版本为必需</li><li>检测失败时需手动指定 Go Root 路径</li></ul><h2 id="环境变量" tabindex="-1">环境变量 <a class="header-anchor" href="#环境变量" aria-label="Permalink to &quot;环境变量&quot;">​</a></h2><p>设计器会自动初始化以下 Go 相关环境变量，确保依赖下载正常工作：</p><table tabindex="0"><thead><tr><th>环境变量</th><th>说明</th></tr></thead><tbody><tr><td><code>GOROOT</code></td><td>Go 安装根目录</td></tr><tr><td><code>GOPROXY</code></td><td>Go 模块代理地址</td></tr><tr><td><code>GOSUMDB</code></td><td>Go 校验数据库</td></tr><tr><td><code>PATH</code></td><td>包含 Go 工具链路径</td></tr></tbody></table><h2 id="配置保存" tabindex="-1">配置保存 <a class="header-anchor" href="#配置保存" aria-label="Permalink to &quot;配置保存&quot;">​</a></h2><p>环境配置保存在设计器的全局配置文件 <code>.energy</code> 中，对所有项目生效。修改后点击&quot;保存&quot;按钮即刻生效。</p>',18),n=[r];function i(c,l,h,s,p,g){return o(),e("div",null,n)}const u=t(a,[["render",i]]);export{G as __pageData,u as default};
